1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === QUOTE: Base premiums ===
6	  it("returns premium of 5 G for an empty item list (processing fee only)", () => {
7	    const scenario = {
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote" as const, items: [] }],
10	    };
11	    const result = processScenario(scenario);
12	    expect(result).toEqual({ results: [{ premium: 5 }] });
13	  });
14	  it.todo("calculates base premium of 100 G + 5 G fee for a single sword");
15	  it.todo("calculates base premium for each item type (amulet 60, staff 80, potion 40)");
16	  it.todo("calculates base premium of 25 G per component (rune/moonstone)");
17	  it.todo("applies building block discount: 3 alike components cost 60 G instead of 75 G");
18	  it.todo("does not apply block discount for 4 alike components (block requires exactly 3)");
19	  it.todo("calculates mixed components without block (2 runes + 1 moonstone = 75 G)");
20	  it.todo("applies two separate blocks for 3 runes + 3 moonstones = 120 G");
21	  it.todo("sums base premiums for multiple different items in a policy");
22	
23	  // === QUOTE: Item-specific modifiers ===
24	  it.todo("adds 50% cursed surcharge to the cursed item's base premium only");
25	  it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
26	  it.todo("applies both cursed and high-enchantment surcharges to same item");
27	  it.todo("applies item-specific surcharges only to affected items in multi-item policy");
28	
29	  // === QUOTE: Policy-wide modifiers ===
30	  it.todo("applies 10% first insurance surcharge to policy base premium");
31	  it.todo("applies 20% loyalty discount for customers with >= 2 years");
32	  it.todo("applies 15% follow-up discount on second and subsequent contracts");
33	  it.todo("combines all modifiers: newcomer with cursed sword = 165 G");
34	  it.todo("combines all modifiers: long-standing customer second contract cursed enchanted sword = 160 G");
35	
36	  // === QUOTE: Rounding ===
37	  it.todo("rounds premiums up (in MHPCO's favor)");
38	
39	  // === QUOTE: Errors ===
40	  it.todo("rejects unknown item type with non-zero exit");
41	
42	  // === CLAIM: Standard reimbursement ===
43	  it.todo("reimburses full damage minus 100 G deductible for regular item");
44	  it.todo("applies deductible per damaged item in multi-damage event");
45	  it.todo("reimburses component damage minus deductible");
46	
47	  // === CLAIM: Special clauses ===
48	  it.todo("reimburses enchantment >= 8 damage at 50% then deductible");
49	  it.todo("reimburses dragon material damage fully then deductible");
50	  it.todo("when both dragon and enchantment >= 8 apply, 50% rule wins then deductible");
51	  it.todo("dragon material with enchantment < 8 gets full reimbursement then deductible");
52	
53	  // === CLAIM: Cap ===
54	  it.todo("caps total payout at 2x insurance sum");
55	  it.todo("tracks remaining cap across multiple claims on same policy");
56	  it.todo("reduces payout to remaining cap when cap is nearly exhausted");
57	
58	  // === CLAIM: Errors ===
59	  it.todo("rejects damage to item not covered by policy");
60	  it.todo("rejects more damage entries of a type than policy covers");
61	  it.todo("rejects negative damage amount");
62	
63	  // === CLI integration ===
64	  it.todo("processes a full scenario with quote and claim steps via CLI JSON interface");
65	});
